// integrationReadyWorkload returns a Deployment + ready Pod pair that
// InitializingApp / ResumingApp can observe as "workload ready" via the
// fake client's label selector. The two objects are seeded into the
// controller's fake client at lineage start for lineages that drive
// through Initializing or Resuming.
func integrationReadyWorkload(name, ns string) (*appsv1.Deployment, *corev1.Pod) {
	labels := map[string]string{"app": name}
	started := true
	dep := &appsv1.Deployment{
		ObjectMeta: metav1.ObjectMeta{Name: name, Namespace: ns},
		Spec: appsv1.DeploymentSpec{
			Selector: &metav1.LabelSelector{MatchLabels: labels},
		},
	}
	pod := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{Name: name + "-pod", Namespace: ns, Labels: labels},
		Spec:       corev1.PodSpec{Containers: []corev1.Container{{Name: "main"}}},
		Status: corev1.PodStatus{
			ContainerStatuses: []corev1.ContainerStatus{{Name: "main", Started: &started}},
		},
	}
	return dep, pod
}

// ---------------------------------------------------------------------------
// types
// ---------------------------------------------------------------------------

type driverKind int

const (
	driverReconcile driverKind = iota
	driverHandlerInstall
	driverHandlerStop
	driverHandlerResume
	driverHandlerApplyEnv
	driverHandlerUpgrade
	driverHandlerUninstall
	driverHandlerCancel
)

func (k driverKind) opLabel() appv1alpha1.OpType {
	switch k {
	case driverHandlerInstall:
		return appv1alpha1.InstallOp
	case driverHandlerStop:
		return appv1alpha1.StopOp
	case driverHandlerResume:
		return appv1alpha1.ResumeOp
	case driverHandlerApplyEnv:
		return appv1alpha1.ApplyEnvOp
	case driverHandlerUpgrade:
		return appv1alpha1.UpgradeOp
	case driverHandlerUninstall:
		return appv1alpha1.UninstallOp
	case driverHandlerCancel:
		return appv1alpha1.CancelOp
	}
	return ""
}

// lineageStep is one named step in a lineage. Each step represents a single
// transition that is observable on NATS (state + message + reason).
//
// Named lineageStep (not driver) to avoid colliding with helm's
// helm.sh/helm/v3/pkg/storage/driver package, which the controllers
// package transitively imports.
type lineageStep struct {
	// label is the transition arrow shown in the dump, e.g. "downloading->installing".
	label string
	// kind is the action that drives the transition: a Reconcile tick or
	// a specific handler write. Handler kinds also default the op recorded
	// in the dump (see opLabel) when the case otherwise leaves it implicit.
	kind driverKind
	// setup configures ctrlFakes before the step runs. Setup is cumulative
	// across steps unless explicitly reset; the previous step's leftover
	// state stays in place. May be nil.
	setup func(*ctrlFakes)
	// timeout, when true, stamps a stale Status.StatusTime onto the AM
	// before the step runs, so Reconcile's IsTimeout->Cancel branch fires.
	timeout bool
	// annotations are merged into the AM's metadata.annotations before the
	// step runs. Used for e.g. api.AppPreUpgradeStateKey.
	annotations map[string]string
	// overrideValidation, when true, swaps r.Deps.RunInstallValidation to a
	// rejecting validator for this step only.
	overrideValidation bool
	// wantState is the expected Status.State after the step completes.
	// Empty means no check (used for branches whose terminal state varies
	// or for steps that intentionally land in an unverified state).
	wantState appv1alpha1.ApplicationManagerState
}

// lineage is an ordered sequence of steps starting from <none>.
type lineage struct {
	name string
	// typ is the AM's Spec.Type used by the install handler at lineage start.
	typ appv1alpha1.Type
	// wr is the workloadReplicas hint passed to buildIntegrationAMAnnotated.
	wr bool
	// extraObjs are seeded into the fake client at lineage start.
	extraObjs []client.Object
	// steps are executed in order.
	steps []lineageStep
}

// chain concatenates a prefix slice with additional steps, producing a
// fresh slice. Use this instead of `append(prefix, more...)` directly to
// avoid Go's append-aliasing footgun when the same prefix function is
// reused across multiple lineages.
func chain(prefix []lineageStep, more ...lineageStep) []lineageStep {
	out := make([]lineageStep, 0, len(prefix)+len(more))
	out = append(out, prefix...)
	out = append(out, more...)
	return out
}

