// truncateDiff caps `s` at maxLines lines. If maxLines <= 0 it returns
// the input unchanged. Returns the (possibly trimmed) text and the
// number of lines that were dropped.
func truncateDiff(s string, maxLines int) (string, int) {
	if maxLines <= 0 {
		return s, 0
	}
	lines := strings.SplitAfter(s, "\n")
	if len(lines) <= maxLines {
		return s, 0
	}
	return strings.Join(lines[:maxLines], ""), len(lines) - maxLines
}

// edgesBlockedOnSeams enumerates reconcile-driven edges that exist in
// production and are listed in appstate.ReconcileDrivenTransitions but
// cannot yet be lineage-driven end-to-end. Each entry must reference an
// open seam-refactor justification: removing one without addressing the
// referenced seam will cause this allow-list to drift from reality.
//
// The list is the single source of truth for "edge is intentionally
// uncovered". TestStateFlow_Lineages_CoversReconcileEdges treats every
// other edge as a hard failure if a lineage step is missing.
var edgesBlockedOnSeams = map[string]string{
	// UpgradingApp.Exec calls real cluster paths (helm.InitConfig,
	// kubesphere.GetAdminUsername, apputils.GetAppConfig /
	// apputils.GetIndexAndDownloadChart) before the happy-path
	// transitions fire. Only IsAdmin is seamed today; the others must
	// land before these three edges can be driven against fakes.
	"upgrading->initializing":  "blocked on UpgradingApp seam refactor (helm.InitConfig + GetAdminUsername + GetAppConfig)",
	"upgrading->stopped":       "blocked on UpgradingApp seam refactor (same dependency chain as upgrading->initializing)",
	"upgrading->upgradeFailed": "blocked on UpgradingApp seam refactor; helm.upgradeErr is unreachable while pre-helm cluster calls fail first",
}

// TestStateFlow_Lineages_CoversReconcileEdges pins every edge declared in
// pkg/appstate.ReconcileDrivenTransitions to at least one lineage step,
// so a new reconcile-driven transition added to production cannot be
// landed without a corresponding lineage update. Edges that are known to
// be inexpressible against today's seams are allow-listed in
// edgesBlockedOnSeams with a documented justification.
func TestStateFlow_Lineages_CoversReconcileEdges(t *testing.T) {
	covered := map[string]bool{}
	for _, l := range allLineages() {
		for i, s := range l.steps {
			if s.kind != driverReconcile {
				continue
			}
			if i == 0 {
				continue
			}
			from := l.steps[i-1].wantState
			to := s.wantState
			if from == "" || to == "" {
				continue
			}
			covered[from.String()+"->"+to.String()] = true
		}
	}

	for _, edge := range appstate.ReconcileDrivenTransitions {
		key := edge[0].String() + "->" + edge[1].String()
		if !covered[key] {
			if reason, blocked := edgesBlockedOnSeams[key]; blocked {
				t.Logf("edge %s uncovered (allow-listed): %s", key, reason)
				continue
			}
			t.Errorf("ReconcileDrivenTransitions edge %s has no lineage step "+
				"(add a lineage step or, if intentionally inexpressible, an entry "+
				"in edgesBlockedOnSeams)", key)
		}
		if !appstate.IsStateTransitionValid(edge[0], edge[1]) {
			t.Errorf("ReconcileDrivenTransitions edge %s is not in StateTransitions", key)
		}
	}

	// Reverse check: every allow-listed edge must still exist in
	// ReconcileDrivenTransitions, so the list does not silently outlive
	// the seam refactor it's tracking.
	declared := map[string]bool{}
	for _, e := range appstate.ReconcileDrivenTransitions {
		declared[e[0].String()+"->"+e[1].String()] = true
	}
	for k := range edgesBlockedOnSeams {
		if !declared[k] {
			t.Errorf("edgesBlockedOnSeams[%s] is no longer in ReconcileDrivenTransitions — drop the entry", k)
		}
	}
}
